    const normalized = frequency / sampleRate;
    const coeff = 2 * Math.cos(2 * Math.PI * normalized);
    let s0 = 0;
    let s1 = 0;
    let s2 = 0;

    for (let i = 0; i < samples.length; i += 1) {
      s0 = (samples[i] || 0) + coeff * s1 - s2;
      s2 = s1;
      s1 = s0;
    }

    return Math.max(0, s1 * s1 + s2 * s2 - coeff * s1 * s2);
